import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';

const AdGrid = ({ pageNumber = 1 }) => {
  const [squares, setSquares] = useState([]);
  const [isLoading, setIsLoading] = useState(true);
  const navigate = useNavigate();

  // Calculate square numbers for this page
  const startSquare = (pageNumber - 1) * 200 + 1;
  const endSquare = pageNumber * 200;

  useEffect(() => {
    const initializeSquares = () => {
      setIsLoading(true);
      
      // Load purchases from localStorage
      let purchases = {};
      try {
        purchases = JSON.parse(localStorage.getItem('squarePurchases') || '{}');
        console.log('📋 Loaded purchases:', purchases); // Debug log
      } catch (error) {
        console.error('Error loading purchases:', error);
        purchases = {};
      }

      // Create 200 squares for the CURRENT page only
      const squaresForThisPage = Array.from({ length: 200 }, (_, index) => {
        const squareNumber = startSquare + index;
        const purchase = purchases[squareNumber];
        
        console.log(`Square ${squareNumber}:`, purchase); // Debug log
        
        if (purchase && purchase.status === 'active') {
          const endDate = new Date(purchase.endDate);
          const today = new Date();
          
          if (today < endDate) {
            return {
              id: squareNumber,
              isAvailable: false,
              businessName: purchase.businessName,
              logoData: purchase.logoData,
              adText: purchase.adText,
              dealLink: purchase.dealLink,
              endDate: purchase.endDate,
              startDate: purchase.startDate
            };
          } else {
            // Campaign expired - mark as available
            console.log(`Square ${squareNumber} expired`);
            return {
              id: squareNumber,
              isAvailable: true,
              price: '£1/day'
            };
          }
        }
        
        // Available square
        return {
          id: squareNumber,
          isAvailable: true,
          price: '£1/day'
        };
      });

      console.log(`✅ Page ${pageNumber}: Squares ${startSquare}-${endSquare}`);
      console.log(`   Occupied: ${squaresForThisPage.filter(sq => !sq.isAvailable).length}`);
      console.log(`   Available: ${squaresForThisPage.filter(sq => sq.isAvailable).length}`);
      
      setSquares(squaresForThisPage);
      setIsLoading(false);
    };

    initializeSquares();
  }, [pageNumber, startSquare]);

  const handleSquareClick = (square) => {
    if (square.isAvailable) {
      navigate('/purchase', { 
        state: { 
          squareNumber: square.id,
          pageNumber: pageNumber 
        } 
      });
    } else {
      // Open deal link in new tab
      if (square.dealLink) {
        window.open(square.dealLink, '_blank');
      }
    }
  };

  // Debug function to check localStorage
  const debugLocalStorage = () => {
    const purchases = JSON.parse(localStorage.getItem('squarePurchases') || '{}');
    console.log('🔍 DEBUG - All purchases in localStorage:', purchases);
    
    const pagePurchases = Object.keys(purchases)
      .filter(key => {
        const num = parseInt(key);
        return num >= startSquare && num <= endSquare;
      })
      .reduce((obj, key) => {
        obj[key] = purchases[key];
        return obj;
      }, {});
    
    console.log(`🔍 DEBUG - Purchases for page ${pageNumber} (squares ${startSquare}-${endSquare}):`, pagePurchases);
  };

  // Loading state
  if (isLoading) {
    return (
      <div className="grid-container">
        <div className="page-info">
          <h3>Page {pageNumber} - Squares {startSquare} to {endSquare}</h3>
          <p>Loading advertising squares...</p>
          <button onClick={debugLocalStorage} style={{background: '#ffc107', padding: '5px 10px', margin: '10px'}}>
            🔍 Debug Storage
          </button>
        </div>
        <div className="squares-grid">
          {Array.from({ length: 200 }).map((_, i) => (
            <div key={i} className="square loading">
              <div className="square-text">Loading...</div>
            </div>
          ))}
        </div>
      </div>
    );
  }

  const occupiedCount = squares.filter(square => !square.isAvailable).length;
  const availableCount = squares.filter(square => square.isAvailable).length;

  return (
    <div className="grid-container">
      <div className="page-info">
        <h3>Page {pageNumber} - Squares {startSquare} to {endSquare}</h3>
        <div className="page-stats">
          <span className="occupied-stat">{occupiedCount} Occupied</span>
          <span className="available-stat">{availableCount} Available</span>
          <button onClick={debugLocalStorage} className="btn-debug">
            🔍 Debug
          </button>
        </div>
        <p>Click any available square to advertise your business for just £1 per day!</p>
      </div>
      
      <div className="squares-grid">
        {squares.map(square => (
          <div
            key={square.id}
            className={`square ${square.isAvailable ? 'available' : 'occupied'}`}
            onClick={() => handleSquareClick(square)}
            title={
              square.isAvailable 
                ? `Square #${square.id}\nClick to purchase - £1 per day` 
                : `${square.businessName}\nClick to visit their deal page`
            }
          >
            {square.isAvailable ? (
              <>
                <div className="square-content">
                  <div className="square-text">BUY THIS SQUARE</div>
                  <div className="square-price">£1 PER DAY</div>
                  <div className="square-number">#{square.id}</div>
                </div>
              </>
            ) : (
              <>
                <div className="square-content">
                  {square.logoData && (
                    <img 
                      src={square.logoData} 
                      alt={square.businessName} 
                      className="occupied-logo" 
                      onError={(e) => {
                        console.error('Error loading logo for square:', square.id);
                        e.target.style.display = 'none';
                      }}
                    />
                  )}
                  <div className="business-name">{square.businessName}</div>
                  <div className="square-number">#{square.id}</div>
                </div>
              </>
            )}
          </div>
        ))}
      </div>
    </div>
  );
};

export default AdGrid;
